import { React, useState } from 'react'
import { Box, Button, TextField, Link, Typography } from '@material-ui/core';
import { makeStyles } from '@material-ui/styles';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

import Cookies from 'js-cookie';

const useStyle = makeStyles(theme => {
    return {
        root: {
            '& .MuiInputBase-root': {
                marginBottom: theme.spacing(1)
            },
            '& .MuiInputBase-input': {
                padding: theme.spacing(2)
            },
            '& .MuiLink-root': {
                color: '#162276',
            }
        },
        form: {
            margin: '0 auto',
            maxWidth: '350px'
        },
        btn: {
            width: '100%',
            margin: '12px 0'
        }
    }
});

export default function StudentLogin({handleChangeToTeacher}) {
    const navigate = useNavigate();
    const classes = useStyle();

    const [error, setError] = useState(false);

    const [data, setData] = useState({
        studentID: '',
        password: ''
    })

    const handleChange = (event) => {
        const name = event.target.name;
        const value = event.target.value;

        setError(false)
        setData(data => ({ ...data, [name]: value }));
    }



    const handleSubmit = (event) => {
        event.preventDefault();
        const sendData = {
            studentID: data.studentID,
            password: data.password
        }
        axios.post('https://ursacapi.000webhostapp.com/api/studentLogin.php', JSON.stringify(sendData))
            .then((response) => {
                console.log(response);

                Cookies.set('idLoggedIn', response.data, {
                    expires: 1,
                    path: '/',
                    sameSite: 'strict'
                });

                if (response.data === 'Invalid') {
                    setError(true);
                } else {
                    navigate('/studentDashboard');
                }
            })
            .catch((error) => {
                console.log(error);
            })
    }


    // const [position, setPosition] = useState('Student');

    return (
        <Box>

            {/* <FormHelperText>
                                Please select your position first.
                            </FormHelperText>
                            <TextField
                                onChange={handleChangeSelect}
                                value={position}
                                select
                                name='position'
                                variant='outlined'
                                type='text'
                                autoComplete='off'
                                fullWidth
                                required
                            >
                                <MenuItem value='Student'>Student</MenuItem>
                                <MenuItem value='Teacher'>Teacher</MenuItem>
                            </TextField> */}

            <form className={classes.form} onSubmit={handleSubmit} method='POST' >
                <Typography variant='h4' align='center' >
                    Student
                </Typography>

                <TextField
                    onChange={handleChange}
                    value={data.studentID}
                    placeholder='Student ID'
                    name='studentID'
                    variant='outlined'
                    type='text'
                    error={error}
                    autoComplete='off'
                    fullWidth
                    required
                />

                <TextField
                    onChange={handleChange}
                    value={data.password}
                    placeholder='Password'
                    name='password'
                    variant='outlined'
                    type='password'
                    helperText={error && 'Wrong Credentials!'}
                    error={error}
                    fullWidth
                    required
                />

                <Button
                    type='submit'
                    name='save'
                    className={classes.btn}
                    size='large'
                    variant='contained'
                    color='secondary'>
                    LOGIN
                </Button>

                <center>
                    <div>
                        <Typography variant='caption'>
                            <Link href="#">
                                Forgot Password?
                            </Link>
                        </Typography>
                    </div>
                    <div>
                        <Link onClick={handleChangeToTeacher}>
                            <Typography variant='caption'>
                                Teacher Login.
                            </Typography>
                        </Link>
                    </div>
                </center>

            </form>

        </Box>
    )
}
